<SpellBlock id="monster-khaei--spells-monster-spellblock-1" sla={{"cl":4,"con":"+5","content":[{"constant":true,"content":<Link to="/spell/blur">blur</Link>},{"will":true,"content":<Link to="/spell/dancing_lights">dancing lights</Link>}]}} />
